import { AttachInternals, Component, Element, Event, EventEmitter, h, Host, Listen, Prop, State, Watch } from '@stencil/core';
import { DropdownItemElement, DropdownLocation, DropdownRequirementIndicator, DropdownSelectionMode, DropdownValueItem, isDropdownItemElement } from './wdpr-dropdown.model';
import { generateRandId } from '../../utils/utils';
import { findNextEnabledIndex, getInitialFocusIndex } from './wdpr-dropdown.utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { InlineMessageSize } from '../wdpr-inline-message/wdpr-inline-message.model';
import { RadialLoaderSize, RadialLabelPlacement } from '../wdpr-radial-loader/wdpr-radial-loader.model';

@Component({
  tag: 'wdpr-dropdown',
  styleUrl: 'wdpr-dropdown.css',
  scoped: true,
  formAssociated: true,
})
export class WdprDropdown {
  private _listId: string;
  private _dropdownId: string;
  private _defaultCheckedIds: string[] = [];
  private _slotObserver: MutationObserver;
  private _resizeObserver: ResizeObserver;
  private _listEl: HTMLDivElement | null = null;
  private _cachedItems: DropdownItemElement[] | null = null;

  @Element() el: HTMLWdprDropdownElement;

  @AttachInternals() internals: ElementInternals;

  @State() _expanded: boolean = false;
  @State() _measuredMaxHeight: string | null = null;
  @State() _readyToShow: boolean = false;
  @State() _selectedValues: Set<DropdownValueItem> = new Set();
  @State() _focusedIndex: number = -1;
  @State() _leadingIcon?: HTMLSlotElement | null;
  @State() _activeDescendantId?: string = undefined;

  /**
   * The value to set/clear in the dropdown.
   * Use the item's **label** (display text), not the item's `value` attribute.
   * Examples: "New York", "London" — not "new-york", "london"
   */
  @Prop({ reflect: true }) value: string = '';
  @Prop() mode: DropdownSelectionMode = 'single';
  @Prop() label: string = '';
  @Prop() helperText: string = '';
  @Prop({ reflect: true }) location: DropdownLocation = 'below';
  @Prop() required: boolean = false;
  @Prop() name?: string;
  @Prop() readonly: boolean = false;
  @Prop() disabled: boolean = false;
  @Prop() error: boolean = false;
  @Prop() noDivider: boolean = false;
  @Prop() maxViewableItems: number | null = null;
  @Prop() requirementIndicator: DropdownRequirementIndicator = 'none';
  @Prop({ attribute: 'a11y-label' }) a11yLabel!: string;

  @Prop() isLoading: boolean = false;
  @Prop() loadingText: string = 'Loading...';
  @Prop() loaderSize: RadialLoaderSize = 'medium';
  @Prop() loaderLabelPlacement: RadialLabelPlacement = 'inline';
  @Prop() showLoaderLabel: boolean = true;
  @Prop() emptyText: string = 'No results.';
  @Prop() emptyTextSize: InlineMessageSize = 'default';
  @Prop() isErrorLoading: boolean = false;
  @Prop() errorText: string = 'Failed to load items. Please try again.';
  @Prop() errorTextSize: InlineMessageSize = 'default';

  @Event() wdprLeadingIconClick: EventEmitter<void>;
  @Event() wdprSelectionChange: EventEmitter<{ selectedValues: { id: string; value: string; label: string }[] }>;

  @Watch('_selectedValues')
  updateSelectedValues() {
    this._syncSelectionItemsState();
    this._updateFormValue();
  }

  @Watch('_expanded')
  handleExpandedChange(newValue: boolean) {
    if (!newValue) {
      this._removeAriaActivedescendant();
      this._setFocusIndex(null);
    }
  }

  @Watch('maxViewableItems')
  handleMaxViewableItemsChange() {
    requestAnimationFrame(() => {
      this._measureItemHeights();
    });
  }

  @Watch('name')
  @Watch('required')
  @Watch('disabled')
  @Watch('mode')
  formPropsChanged() {
    this._updateFormValue();
  }

  @Watch('value')
  handleValueChanged() {
    this._syncSelectionFromValue();
  }

  @Listen('wdprSelect')
  handleItemSelect(event: CustomEvent<{ value: string; label: string; selected: boolean; id: string }>) {
    event.stopPropagation();
    const {
      detail: { value, label, selected, id },
    } = event;
    this._updateSelectedValues(value, label, selected, id);

    if (!this._isMultipleMode) {
      this._closeDropdown();
    }
  }

  @Listen('click', { target: 'document' })
  handleClickOutside(event: MouseEvent) {
    if (this._expanded && this.el && !event.composedPath().includes(this.el)) {
      this._closeDropdown();
    }
  }

  componentWillLoad() {
    this._listId = `wdpr-dropdown-list-${generateRandId()}`;
    this._dropdownId = `wdpr-dropdown-${generateRandId()}`;
    this._resizeObserver = new ResizeObserver(() => this._measureItemHeights());
    this._leadingIcon = this.el.querySelector('[slot="leading-icon"]');
  }

  componentDidLoad() {
    requestAnimationFrame(() => {
      this._initAllItems();
      this._measureItemHeights();
      this._syncSelectionFromValue();
      if (this._listEl) {
        this._slotObserver.observe(this._listEl, { childList: true, subtree: true });
      }
    });

    this._slotObserver = new MutationObserver(mutations => {
      const items = mutations.flatMap(m => Array.from(m.addedNodes)).filter((n): n is HTMLElement => n.nodeType === Node.ELEMENT_NODE);

      if (items.length === 0) return;

      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      Promise.all(items.map(el => ('componentOnReady' in el ? (el as any).componentOnReady() : Promise.resolve()))).then(() => {
        this._invalidateItemsCache();
        this._initAllItems();
        this._measureItemHeights();
        this._syncSelectionFromValue();
      });
    });
  }

  connectedCallback() {
    this.internals?.form?.addEventListener('reset', this._handleFormReset);
  }

  disconnectedCallback() {
    this.internals?.form?.removeEventListener('reset', this._handleFormReset);
    this._slotObserver?.disconnect();
    this._resizeObserver?.disconnect();
  }

  private _getSelectedFormValues(): string[] {
    return Array.from(this._selectedValues).map(item => item.value);
  }

  private _updateValidity(selectedValues?: string[]) {
    if (this.disabled) {
      this.internals?.setValidity?.({});

      return;
    }

    const values = selectedValues ?? this._getSelectedFormValues();
    if (this.required && values.length === 0) {
      this.internals?.setValidity?.({ valueMissing: true }, 'An option is required');

      return;
    }

    this.internals?.setValidity?.({});
  }

  private _updateFormValue() {
    const selectedValues = this._getSelectedFormValues();
    const formValue = this._isMultipleMode ? selectedValues.join(',') : selectedValues[0] ?? '';
    const hasValue = !!formValue;
    const shouldSubmit = !this.disabled && !!this.name && hasValue;

    this.internals?.setFormValue?.(shouldSubmit ? formValue : null);
    this._updateValidity(selectedValues);
  }

  private _handleFormReset = () => {
    const defaultChecked = new Set(this._defaultCheckedIds);
    this._selectedValues = new Set(Array.from(this._selectedValues).filter(item => defaultChecked.has(item.id)));
  };

  private _closeDropdown() {
    this._expanded = false;
  }

  private _getAllListItems(): DropdownItemElement[] {
    if (!this._cachedItems?.length) {
      this._cachedItems = Array.from(this.el?.querySelectorAll('[data-dropdown-item]')).filter(isDropdownItemElement);
    }

    return this._cachedItems;
  }

  private async _initAllItems(): Promise<void> {
    const allItems = this._getAllListItems();

    if (allItems.length === 0) return;

    this._resizeObserver.disconnect();
    this._resizeObserver.observe(allItems[0]);

    const lastItem = allItems[allItems.length - 1];
    const groupLastItems = this._groupLastItems();

    for (const item of allItems) {
      item.mode = this.mode;

      if (this.noDivider || item === lastItem || groupLastItems.has(item)) {
        if (typeof item.hideDivider === 'function') {
          await item.hideDivider();
        }
      }
    }
  }

  private _syncSelectionFromValue(): void {
    const allItems = this._getAllListItems();
    const selectedLabels = this._isMultipleMode
      ? this.value
          .split(',')
          .map(v => v.trim())
          .filter(Boolean)
      : [this.value];

    const selectedSet = new Set<DropdownValueItem>();

    for (const item of allItems) {
      if (selectedLabels.includes(item.label) && !item.disabled) {
        selectedSet.add({ value: item.value, label: item.label, id: item.id });
      }
    }

    this._selectedValues = selectedSet;
    this._defaultCheckedIds = Array.from(selectedSet).map(item => item.id);
  }

  private _groupLastItems(): Set<DropdownItemElement> {
    const groupElements = Array.from(this.el.querySelectorAll('wdpr-dropdown-group'));

    const lastItems: DropdownItemElement[] = [];

    for (const group of groupElements) {
      const items = Array.from(group.querySelectorAll('[data-dropdown-item]')).filter(isDropdownItemElement);

      const lastItem = items[items.length - 1];

      if (lastItem) {
        lastItems.push(lastItem);
      }
    }

    return new Set<DropdownItemElement>(lastItems);
  }

  private _handleLeadingIconSlotChange = () => {
    this._leadingIcon = this.el.querySelector('[slot="leading-icon"]');
  };

  private _updateSelectedValues(value: string, label: string, selected: boolean, id: string): void {
    if (!this._isMultipleMode) {
      this._updateValuesFromSingleSelection(value, label, selected, id);
    } else {
      this._updateValuesFromMultipleSelection(value, label, selected, id);
    }

    this.wdprSelectionChange.emit({ selectedValues: Array.from(this._selectedValues) });
  }

  private _updateValuesFromSingleSelection(value: string, label: string, selected: boolean, id: string): void {
    this._selectedValues = selected ? new Set([{ value, label, id }]) : new Set();
  }

  private _updateValuesFromMultipleSelection(value: string, label: string, selected: boolean, id: string): void {
    const newSelectedValues = new Set(this._selectedValues);
    if (selected) {
      newSelectedValues.add({ value, label, id });
    } else {
      Array.from(newSelectedValues).forEach(item => {
        if (item.value === value && item.id === id) newSelectedValues.delete(item);
      });
    }
    this._selectedValues = newSelectedValues;
  }

  private _syncSelectionItemsState(): void {
    const selectedIds = new Set(Array.from(this._selectedValues).map(s => s.id));
    this._getAllListItems().forEach(item => {
      item.selected = selectedIds.has(item.id);
    });
  }

  /**
   * Measures the height of the dropdown list and sets the max height for scrollable lists.
   * Calculates based on the number of visible items and their bounding rectangles.
   */
  private _measureItemHeights(): void {
    this._readyToShow = false;

    if (this.maxViewableItems == null || this.maxViewableItems <= 0) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const allListItems: DropdownItemElement[] = this._getAllListItems();
    const listbox = this.el?.querySelector('.listbox');

    if (!listbox || allListItems.length === 0) {
      this._readyToShow = true;

      return;
    }

    if (allListItems.length <= this.maxViewableItems) {
      this._measuredMaxHeight = null;
      this._readyToShow = true;

      return;
    }

    const targetItem = allListItems[this.maxViewableItems - 1];
    const wrapperRect = listbox.getBoundingClientRect();
    const itemRect = targetItem.getBoundingClientRect();
    const itemHeight = targetItem.offsetHeight;

    if (itemHeight === 0) return;

    let calculatedHeight = Math.ceil(itemRect.bottom - wrapperRect.top);

    // Add Wrapper Padding (if available)
    const style = window.getComputedStyle(listbox);
    const paddingBottom = parseFloat(style.paddingBottom) || 0;
    calculatedHeight += paddingBottom;
    const newHeight = `${calculatedHeight}px`;

    if (this._measuredMaxHeight !== newHeight) {
      this._measuredMaxHeight = newHeight;
    }

    this._readyToShow = true;
  }

  private _renderDropdown(): JSX.Element {
    return (
      <div
        class="dropdown"
        tabindex={this.disabled ? -1 : 0}
        id={this._dropdownId}
        role="combobox"
        data-has-value={this._hasValueAttr}
        aria-invalid={this.error.toString()}
        aria-disabled={this.disabled.toString()}
        aria-readonly={this.readonly.toString()}
        aria-expanded={this._expanded.toString()}
        aria-controls={this._listId}
        aria-labelledby={`${this._dropdownId}-label`}
        aria-required={this.required.toString()}
        aria-haspopup="listbox"
        aria-describedby={this.helperText ? `${this._dropdownId}-helper-text` : undefined}
        aria-activedescendant={this._activeDescendantId}
        onClick={this._handleComboboxClick}
      >
        {this._leadingIcon && !this.readonly && (
          <span onClick={this._onLeadingClick} class="dropdown__icon-wrapper">
            {/* Although this is an open slot, the expected usage is to place an wdpr-icon-library here. */}
            <slot onSlotchange={this._handleLeadingIconSlotChange} name="leading-icon" />
          </span>
        )}

        <div class="dropdown__inner-wrapper">
          <span class="dropdown__display-value">{this._displayValue}</span>
          <span class="dropdown__label" id={`${this._dropdownId}-label`}>
            {this.label} {this._requirementLabel}
          </span>
        </div>

        {!this.readonly && (
          <span class="dropdown__icon-wrapper">
            <wdpr-icon-library icon={this._dropdownIcon} size="medium" decorative />
          </span>
        )}
      </div>
    );
  }

  private _renderList(): JSX.Element {
    const isScrollable = this.maxViewableItems != null && this.maxViewableItems > 0;

    return (
      <div
        ref={el => (this._listEl = el)}
        class="listbox"
        role="listbox"
        aria-multiselectable={this._isMultipleMode ? 'true' : undefined}
        id={this._listId}
        tabindex={isScrollable ? 0 : undefined}
        aria-label={this.a11yLabel}
      >
        <slot />
      </div>
    );
  }

  private _renderInlineMessage(): JSX.Element {
    return (
      this.helperText && (
        <div class="dropdown-inline-message-wrapper">
          <wdpr-inline-message id={`${this._dropdownId}-helper-text`} variant={this.error ? 'error' : 'informational'} size="small" role="status">{this.helperText}</wdpr-inline-message>
        </div>
      )
    );
  }

  private _renderListWrapper(): JSX.Element {
    const listContainerClasses = this._isListVisible ? 'dropdown-list-container-visible' : 'dropdown-list-container-invisible';

    return (
      <div class={`dropdown-list-container ${listContainerClasses}`} style={{ height: this._measuredMaxHeight }}>
        {this._renderList()}
      </div>
    );
  }

  private _renderStatusMessage(): JSX.Element | null {
    const isEmpty = this._getAllListItems().length === 0;

    if (!this._expanded) return null;
    if (this.isLoading)
      return (
        <div class="loading-container">
          <wdpr-radial-loader size={this.loaderSize} label={this.loadingText} labelPlacement={this.loaderLabelPlacement} showLabel={this.showLoaderLabel} />
        </div>
      );
    if (isEmpty && !this.isErrorLoading && !this.isLoading)
      return (
        <div class="empty-container">
          <wdpr-inline-message variant="informational" size={this.emptyTextSize}>{this.emptyText}</wdpr-inline-message>
        </div>
      );
    if (this.isErrorLoading && !this.isLoading)
      return (
        <div class="error-container">
          <wdpr-inline-message variant="error" size={this.errorTextSize}>{this.errorText}</wdpr-inline-message>
        </div>
      );

    return null;
  }

  private _onLeadingClick = (event: Event) => {
    event.stopPropagation();
    this.wdprLeadingIconClick.emit();
  };

  private _handleComboboxClick = (): void => {
    if (this.disabled || this.readonly) return;

    this._expanded = !this._expanded;
  };

  /**
   * Handles keyboard navigation and accessibility for the dropdown.
   * Supports arrow keys, Enter, Space, Escape, and Tab for navigation and selection.
   * @param ev The keyboard event
   */
  private _handleKeydown = (ev: KeyboardEvent): void => {
    if (this.disabled || this.readonly) return;

    const items = this._getAllListItems();

    // Handle Enter and Space for toggle/selection
    if (ev.key === KEYBOARD_KEYS.ENTER || ev.key === KEYBOARD_KEYS.SPACE) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);
      } else {
        const focusedItem = items[this._focusedIndex];
        if (focusedItem && !focusedItem.disabled) {
          focusedItem.click();
        }
      }

      return;
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_DOWN) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'down');
        this._focusItemAtIndex(startIndex, items);

        return;
      }
      // Move focus to next enabled item
      const nextIndex = findNextEnabledIndex(items, this._focusedIndex, 'down');
      this._focusItemAtIndex(nextIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ARROW_UP) {
      ev.preventDefault();
      if (!this._expanded) {
        this._expanded = true;
        const startIndex = getInitialFocusIndex(items, 'up');
        this._focusItemAtIndex(startIndex, items);

        return;
      }
      // Move focus to previous enabled item
      const prevIndex = findNextEnabledIndex(items, this._focusedIndex, 'up');
      this._focusItemAtIndex(prevIndex, items);
    }

    if (ev.key === KEYBOARD_KEYS.ESCAPE && this._expanded) {
      ev.preventDefault();
      ev.stopPropagation();
      this._closeDropdown();
    }

    if (ev.key === KEYBOARD_KEYS.TAB) {
      this._closeDropdown();
    }
  };

  /**
   * Sets focus to the item at the given index, updates ARIA attributes, and scrolls it into view.
   * @param index The index of the item to focus
   * @param items The array of dropdown items
   */
  private _focusItemAtIndex(index: number, items: DropdownItemElement[]): void {
    this._setFocusIndex(index);
    this._updateAriaActivedescendant(items[index]);

    // Scroll the focused item into view
    const focusedItem = items[index];
    if (focusedItem) {
      this._scrollIntoItem(focusedItem);
    }
  }

  private _setFocusIndex(index: number | null): void {
    const items = this._getAllListItems();
    items.forEach((item, i) => {
      item.isFocused = i === index;
    });

    this._focusedIndex = index == null ? -1 : index;
  }

  private _updateAriaActivedescendant(item: DropdownItemElement): void {
    this._activeDescendantId = item?.id;
  }

  private _removeAriaActivedescendant(): void {
    this._activeDescendantId = undefined;
  }

  private _scrollIntoItem(item: DropdownItemElement): void {
    const listbox = this.el?.querySelector('.listbox');
    if (listbox) {
      item.scrollIntoView({ block: 'nearest', inline: 'nearest' });
    }
  }

  private _invalidateItemsCache(): void {
    this._cachedItems = null;
  }

  private get _requirementLabel(): HTMLElement | null {
    if (this.requirementIndicator === 'required') return <span aria-hidden="true">*</span>;

    if (this.requirementIndicator === 'optional') return <span>(Optional)</span>;

    return null;
  }

  private get _isMultipleMode(): boolean {
    return this.mode === 'multiple';
  }

  private get _hasSelection(): boolean {
    return this._selectedValues.size > 0;
  }

  private get _emptyDisplayValue(): string {
    return this.readonly ? '--' : '';
  }

  private get _displayValue(): string {
    if (!this._hasSelection) return this._emptyDisplayValue;

    return Array.from(this._selectedValues)
      .map(item => item.label)
      .join(', ');
  }

  private get _hasValueAttr(): 'true' | 'false' {
    return this.readonly || this._hasSelection ? 'true' : 'false';
  }

  private get _dropdownIcon(): string {
    return this._expanded ? 'expand-show-less' : 'expand-show-more';
  }

  private get _isListVisible(): boolean {
    return this._readyToShow && this._expanded && !this.isLoading && this._getAllListItems().length > 0 && !this.isErrorLoading;
  }

  render() {
    return (
      <Host onKeyDown={this._handleKeydown}>
        <div class="dropdown-wrapper">
          {this._renderDropdown()}
          {this._renderInlineMessage()}
          {this._renderListWrapper()}
          {this._renderStatusMessage()}
        </div>
      </Host>
    );
  }
}
